var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"하나, 둘, 셋~","JPN":"3、2、1、せーのっ！","ENG":"One, two, three...","TWN":"1、2、3～"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"퇴원 축하해! 레이첼 언니!","JPN":"退院おめでとう！　レイチェルお姉ちゃん！","ENG":"Welcome back! Rachel!","TWN":"瑞秋姊姊，恭喜你出院！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PISTOL"},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"다들 고마워! 보육원생 레이첼, 덕분에 멀쩡하게 복귀했습니다!","JPN":"みんなありがとう！　レイチェル・ドッズ、みんなのおかげで元気に復帰しました！","ENG":"Thank you, everyone. I'm out of the hospital and as good as new!","TWN":"謝謝大家，育幼院院生 瑞秋平安到家！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 아야야야…….","JPN":"いたっ、いたたたた……","ENG":"Ow, owww...","TWN":"唉唷唷……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그렇게 까불다가 죽을 고비 넘겨 놓고서는 여전하다, 이것아.","JPN":"調子に乗りすぎてとんでもない目にあったくせに、変わらないなこいつは。","ENG":"Haven't you learned anything after almost getting yourself killed?","TWN":"你再這麼調皮，到時候又樂極生悲！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"너 병원에 있을 때 그 의사 선생님한테 인사는 제대로 드렸니?","JPN":"入院していた時の担当の先生にはちゃんと挨拶してきたか？","ENG":"Did you even thank your doctor properly before you left?","TWN":"你在醫院時，有好好跟醫生打招呼嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"당연하죠. 오늘 퇴원할 때도 뵙고 왔는데요.","JPN":"もちろんです。さっき退院手続きする時も会ってきましたよ。","ENG":"Of course. I met her right before I left today.","TWN":"那當然囉！今天要出院時，我也有去跟醫生打招呼好嗎！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"쾌유해서 다행이에요. 졸업한 학생들 만나러 <color=#ffd34c>우연히</color> 오지 않았더라면 큰일이었겠어요.","JPN":"快癒してよかったです。<color=#ffd34c>偶然</color>私が卒業生に会うためにこちらに来ていなかったら、大変なことになっていたと思います。","ENG":"Thank goodness you're all better now. It's a good thing that I <color=#ffd34c>happened to swing by</color> to meet some of my former students.","TWN":"恭喜你康復，要不是我<color=#ffd34c>剛好</color>來看畢業的學生，可就糟糕囉！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 네! 고맙습니다, 선생님!","JPN":"はい！　助かりました、先生！","ENG":"Oh, yes! Thank you, ma'am!","TWN":"是！謝謝醫生！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"후훗. 뭘요. 오랜만에 저도 실력을 발휘할 수 있어서 의욕이 생기던 걸요.","JPN":"フフッ、こちらこそ、私も久しぶりに実力を発揮できていい刺激になりましたよ。","ENG":"Haha. No worries. I enjoyed the chance to brush up on my skills again too.","TWN":"呵呵，不用客氣，我也久違地可以這樣大展身手。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"안 그러니, 제자야?","JPN":"そう思わない、弟子？","ENG":"Isn't that right, my dear protege?","TWN":"助教，你說對不對？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"하, 하하……. 네……. 그러니 제가 아직까지 붙어 있죠…….","JPN":"あ、はは……はい……だから私が辞めずに残っているわけです……","ENG":"Haha... Ha... Of course… Why else would I keep sticking around…","TWN":"哈，哈哈……對……否則我怎麼會還沒離開……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"으응? 뭐라고?","JPN":"うん？　なんか言った？","ENG":"Huh? What was that?","TWN":"嗯？你說什麼？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"제, 제가 무슨 소리 했나요?! 아무것도 아닙니다!","JPN":"わ、私何か言いましたか！？　何でもないです！","ENG":"D-Did I say something?! It's nothing!","TWN":"我…我有說什麼嗎？我什麼都沒說！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"몸에 후유증은 여전할 거예요. 대표적으로 그 등의 화상.","JPN":"後遺症は残るでしょう。例えばその背中の火傷。","ENG":"You'll still suffer from various sequelae. Especially that burn on your back.","TWN":"身體會留下後遺症，像是背上的燒傷。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"흉터는 물론이고, 정기적으로 병원에서 진찰 받아야 해요.","JPN":"傷跡はもちろん、定期的に病院で診察を受けなければなりません。","ENG":"It'll scar for sure. And you should get it periodically checked out at the hospital.","TWN":"疤是一定的，你要定期到醫院回診喔。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"비누칠도 되도록이면 살살 하고. 아까운 미모를 잃지 않았으니 더 열심히 가꿔야죠?","JPN":"洗う時もできる限り優しく。幸いそのキレイな顔には傷跡が残ってないから、これからも大事にしないとですね。","ENG":"Make sure you lather the soap gently on the affected area. You were lucky enough to hang onto your beauty. You should take extra good care of it now.","TWN":"搓肥皂的時候，也要盡可能動作溫柔一點，既然保住這張漂亮的臉，當然要好好對待它囉！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_ACADEMY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"제가 보기에는 그래도 수술 겁나 잘 됐다 싶던데, 어때요?","JPN":"素人の私がみても手術はちょーうまくいったと思いますよ！　ほら、どうですか？","ENG":"I thought the surgery went super well though. How does it look?","TWN":"我自己覺得手術滿順利的，你們覺得呢？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"외투 걸쳐, 이 녀석아! 다 커 갖고 애들 보는 앞에서 무슨 짓이야!","JPN":"こらこら、服を着なさい！　いい年して子どもたちの前で何をしてるんだ！","ENG":"Put your coat back on, you fool! There are kids watching!","TWN":"你這丫頭，把外套穿好！在大家面前這樣成何體統！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"언니, 이거 받아. 언니 입원해 있는 동안 우리가 산 스프레이야.","JPN":"お姉ちゃん、これあげる。お姉ちゃんが入院している間、エマたちが買ったスプレーだよ。","ENG":"Here, Rachel. We bought you a can of spray paint while you were in the hospital.","TWN":"姊姊，這個給你，這是我們在姊姊住院時買的噴漆。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"정말? 너희들이 무슨 돈이 있어서?","JPN":"本当に？　あんたたちお金はどうやって貯めたの？","ENG":"Really? How did you guys even afford this?","TWN":"真的嗎？你們哪來的錢？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"말도 마라. 그 돈 모으겠다고 얘들이 동네 들쑤시고 다녀서 혼났어.","JPN":"まったく。お金がほしいからって町中をかき回してこっちが大変だったんだ。","ENG":"Don't even get me started. They've been turning the entire neighborhood upside down to save up for that.","TWN":"別提了，他們為了存錢，翻遍整個難民區，還害我被罵！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"쥐 잡기에 폐지 모으기에……. 자경단이 나더러 요새 애들 굶기냐고 물어보더라.","JPN":"ネズミ捕りに古紙集めに……自警団から最近子どもたちにちゃんとご飯をあげてるのかと散々疑われたんだぞ。","ENG":"They caught rats, collected all the recyclables… The neighborhood watch asked me if I wasn't feeding them properly.","TWN":"他們就是抓老鼠，或是回收廢紙……搞到自衛隊還來問我，最近是不是讓孩子們餓肚子！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"헤헤, 농담으로 한 소리겠죠. 이 동네에서 원장님 마음 넓은 걸 누가 모른다고.","JPN":"へへ、冗談で聞いたんだと思いますよ。この町で院長の心の広さを知らない人はいませんって。","ENG":"Haha, I'm sure they were kidding. Everyone in this neighborhood knows how generous you are.","TWN":"嘿嘿，院長是說笑的吧？難民區裡誰不知道院長心胸廣大！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이마만 봐도 티가 확 나잖아요?","JPN":"心の広さと同じくらい広いそのおでこを見ればわかること！","ENG":"You even generously reflect the sunlight for us with your smooth, shiny head!","TWN":"人家說十個禿子十個善呢！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"너 이 녀석아, 오늘 퇴원한 날이라 봐 주는 거야.","JPN":"こらっ！　まあでも今日は退院日だから大目に見てやる。","ENG":"I'll let that slide, just for today, seeing as you just got out of the hospital.","TWN":"你這丫頭！看在你今天出院的份上放你一馬！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런데 호라이즌은 다시 왔어요?","JPN":"ところでホライズンは？　戻ってきました？","ENG":"By the way, did Horizon come back?","TWN":"不過地平線還有回來嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그 망나니랑은 절대 엮이지 마! 절대로!","JPN":"そいつとは二度と関わるな！　絶対に！","ENG":"Don't you ever get involved with that thug again! Ever!","TWN":"不准你和那種不良少女有牽扯！聽到沒有！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"왜, 왜 갑자기 성질이람.","JPN":"えー急に大声出さないでくださいよ。","ENG":"Woah, why the sudden outburst?","TWN":"為什麼？幹嘛突然發火？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"왜긴 왜야? TV에 대문짝만 하게 재판 받는 모습이 나왔으니까 그렇지!","JPN":"知らないのか？　テレビで裁判を受ける姿が連日報道されていたんだぞ！","ENG":"Why else? They've been showing her trial all over TV!","TWN":"什麼為什麼？因為我在電視上看到他受審的畫面！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"국제적으로 폭행 범죄를 일으키고 다니는 미치광이가 우리 보육원에 들어왔었다니, 어유! 소름 끼쳐!","JPN":"国際的な暴行犯罪を起こすイカれた奴がうちの施設にいたなんて、鳥肌が立つくらいだよ！","ENG":"I can't believe we let an international terrorist in to our orphanage! It still gives me chills to think about it!","TWN":"那種國際罪犯竟然曾經出現在我們育幼院！想到我就覺得可怕！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"맞을 만한 짓을 했으니까 맞았겠지, 뭘.","JPN":"相手が殴られるようなことをしたから殴られたんでしょ。","ENG":"I'm sure they probably deserved it.","TWN":"可是做壞事不是本來就活該被打嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"어허! 레이첼 너! 그런 말 하고 다니면 혼나!","JPN":"こら、レイチェル！　そんなこと言うんじゃない！","ENG":"Shush! Rachel! You'll get yourself into trouble if you say stuff like that out loud!","TWN":"閉嘴！瑞秋！你再說這種話院長會生氣喔！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그러고 보니 요즘 뉴스에 이상하게 말이 없던데……. 너 혹시나 마주치지 않게 조심해야 돼.","JPN":"しかし最近はニュースに出てこないな……二度と絡まれないように気を付けるんだぞ。","ENG":"Strangely enough though, they stopped talking about her on the news recently… Be careful you don't run into her again.","TWN":"不過話說回來，最近好像沒有她的報導……你自己要小心點不要遇到她！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어휴. 오자마자 잔소리.","JPN":"はあ、退院早々小言ばかり。","ENG":"Ugh. You really gotta nag me the moment I get back?","TWN":"真的是，一來就長篇大論。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"어, 어디 가는 거니? 레이첼!","JPN":"ど、どこに行くんだ、レイチェル！？","ENG":"W-where are you going? Rachel!","TWN":"喂，你去哪？瑞秋！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"선물 받은 스프레이 써 봐야죠! 멀리 안 나가요!","JPN":"プレゼントでもらったスプレーを試してきますね！　遠くまで行かないから安心して！","ENG":"I want to try out this new spray paint they got me! I'm not going far!","TWN":"拿到禮物當然就要用囉～我在附近而已！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"오, 레이첼! 멀쩡하네?","JPN":"おお、レイチェル！　元気そうじゃないか！","ENG":"Oh, Rachel! You look perfectly fine!","TWN":"喔，是瑞秋！你沒事啦？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"의사 잘 만난 덕분이지. 요즘 좀 어때?","JPN":"腕のいいお医者さんのおかげだよ。最近どう？","ENG":"Yeah, I had a good doctor. How's everything these days?","TWN":"幸運遇到好醫生的嘛～大家最近好嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"그게 말이야, 교관님께서 네 수술 잘 끝났다는 소식 듣자마자 떠나셨어.","JPN":"それがな、教官がお前の手術が無事に終わったと聞いた後、去っていったんだ。","ENG":"Oh, well… The Instructor left the moment he heard your surgery went well.","TWN":"這個嘛，教官一聽說你的手術順利結束後，就立刻離開了。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐? 왜?! 매점에서 술 빼돌리다가 들켰대?","JPN":"え？　なんで？　コンビニの酒を転売でもしてバレたの？","ENG":"What? Why? Did he get caught stealing booze from the convenience store?","TWN":"什麼？為什麼？被他發現我偷商店的酒嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"으음, 글쎄. 우리도 이유는 못 들었어.","JPN":"さあな。俺らも理由は聞けてない。","ENG":"Hmm, I'm not sure. We didn't exactly hear why either.","TWN":"嗯，不知道，我們也沒聽說原因。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"난 그 때 지하철 수색하러 온 짭새들 때문이라고 생각한다.","JPN":"俺はあの時地下鉄の捜索をしに来たマッポのせいだと思う。","ENG":"I bet it's because of those cops who was snooping around the subway.","TWN":"我認為是因為那時來地鐵搜查的條子！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"그 생글생글 웃고 다니던 여자 경찰! 사실은 무서운 악연으로 묶여 있는 거야!","JPN":"あのニヤニヤと笑っていた女警察！　実は恐ろしい悪縁で結ばれていたとかな！","ENG":"You know, that officer lady with the creepy smile! There must be some kind of bad blood between them!","TWN":"那個笑咪咪的女警官！雖然第一次見面的場合不太好！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"퍽이나 그러겠다.","JPN":"それはないな。","ENG":"Yeah, right.","TWN":"一定是那樣！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"동감이야.","JPN":"同感だわ。","ENG":"Yeah, I don't buy it either.","TWN":"同意！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런데 민우 아저씨가 없으면 어떡해? 오빠들만으로는 어림도 없잖아?","JPN":"でもマツダおじさんなしでこれからどうするの？　お兄ちゃんたちだけじゃ色々無理じゃない？","ENG":"But what are you going to do now that Mr. Minwoo's gone? There's no way you guys can handle this on your own, is there?","TWN":"不過民宇叔叔不在的話，怎麼辦？畢竟你們也沒什麼用。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"그거야 두고 보면 알지 않을까?","JPN":"それはやってみないとわからないぜ。","ENG":"We'll see about that.","TWN":"這還不知道呢～"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"리 오빠?! 니나 언니도 왔네?!","JPN":"リー兄ちゃん？！　ニーナ姉ちゃんも来たの！？","ENG":"Lee?! Nina too?! You're back?","TWN":"李哥哥？！妮娜姊姊也來啦？！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"출세한 사람들이 웬일이래? 그라운드 원에서 태스크포스 일 하는 거 아니었어?","JPN":"出世した人たちがこんなところでどうしたの？　グラウンド・ワンでタスクフォースカンパニーの仕事をしていたんじゃなかったの？","ENG":"What are you big shots doing back here? Didn't you get into a TASKFORCE in Ground One?","TWN":"什麼風把兩位大紅人吹來啦？你們不是在G1辦特遣勢力的事嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"우리 대장님 때문에. 고향에 심상치 않은 일이 터졌다고 해서 걱정이 많더라고.","JPN":"うちの隊長様のせいでな。故郷に物騒な事件が起きたと聞いて心配になって来たんだ。","ENG":"It's all because of our captain here. She was worried sick about what's been going on back in our hometown.","TWN":"還不都是我們隊長，說故鄉發生不尋常的事，害我很擔心。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"뉴스 보자마자 먹던 라면 뿜고 뛰쳐 나가던 건 너야.","JPN":"ニュースを見るやいなや、食べていたカップ麵を噴き出して飛び出てきたのは君だろう。","ENG":"You're the one who darted out the moment you saw the news.","TWN":"是誰一看到新聞，就吐掉嘴裡的泡麵衝出去的？是你好嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"그 사이에 키가 많이 컸네, 레이첼? 요즘 그래피티는 어때?","JPN":"見ない間に背が伸びたな、レイチェル。最近もグラフィティをやってるのか？","ENG":"You've grown taller than the last time we saw you, Rachel. How's the graffiti coming along these days?","TWN":"瑞秋，你這段時間長高不少喔！最近塗鴉如何？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"전보다 더 끝내주지! 언니가 필요하다면 멋진 걸로 즉석에서 하나 해 줄 수도 있는데?","JPN":"もちろん、前より上達したよ！　姉ちゃんが欲しいなら、ちょーイケてるやつを今すぐ描いてあげようか？","ENG":"Oh, I got even better than before! I could make an awesome one right here if you'd like to see!","TWN":"當然是比之前更厲害囉！姊姊想要嗎？我可以立刻畫一幅厲害的給你！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"이 소리는…….","JPN":"この音は……","ENG":"That sound...","TWN":"這個聲音是……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"아, 그러고 보니 마야한테 하트베리 방송 보여 주려고 트렁크에서 태블릿 꺼냈는데…….","JPN":"あ、そういえばマヤにハートベリーの配信を見せようとトランクからタブレットを出しておいたが……","ENG":"Come to think of it, I took out the tablet from the trunk so Maya could watch the HRT Berry show…","TWN":"突然想到，我要給瑪雅看愛心莓果的直播，就從箱子裡拿出平板……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"너 설마 그러고 안 잠궜어?! 그 안에 로켓포 들어 있잖아!","JPN":"もしかして、鍵をかけなかったのか？　トランクの中にはロケット砲が入っているだろ！？","ENG":"Did you forget to lock the trunk?! The RPG's in there!","TWN":"你沒把它關好嗎？！裡面裝的是炸藥欸！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"좀 있다 다시 얘기하자, 레이첼! 험비 피자가게에서 피자 한 판 먹으면서!","JPN":"後でまた話そう、レイチェル！　ハンヴィのピザ屋さんでな！","ENG":"We'll have to catch up later, Rachel! Let's grab a pie at the Humvee Pizzeria!","TWN":"瑞秋，我們晚點再聊！一邊吃披薩一邊聊！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"수고해, 언니!","JPN":"頑張ってね、姉ちゃん！","ENG":"Take care, Nina!","TWN":"姊姊辛苦囉！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그래서 두 사람, 호라이즌 소식은 뭐 들은 거 없어?","JPN":"それで二人は、ホライズンについて何か知らないの？","ENG":"So… Have you two heard anything about Horizon?","TWN":"喂，你們兩個，有聽說什麼地平線的消息嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"아, 그 애 말이지. 별다른 소식은 안 들렸는데…….","JPN":"ああ、あの子か。特に噂とかはなかったが……","ENG":"Oh, that kid? Nothing special, really…","TWN":"喔～你說那個孩子喔，是沒聽到什麼消息……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"4번가에 그 사무실 있잖아. 며칠 전에 갑자기 공사를 하더라고. 누가 사들였나 봐.","JPN":"4番街の事務所があるだろ。数日前から急に工事が始まったんだ。誰かが買い付けたみたいでな。","ENG":"You know that office on 4th Avenue? They started construction there out of the blue a few days ago. Someone must have bought the property.","TWN":"不是在第四大道的辦公室嗎？幾天突然在施工，可能有人買下它吧？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐? 호라이즌네 사무실을?","JPN":"え？　ホライズンの事務所を？","ENG":"What? Horizon's office?","TWN":"什麼？買地平線的辦公室？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"으음. 간판까지 번듯하게 걸렸던데.","JPN":"そう。看板までちゃんとかかっていたよ。","ENG":"Mmhmm. It even had a new sign and all.","TWN":"嗯嗯，還有掛上漂亮的招牌呢～"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"그래. 그런데 이름이 분명…….","JPN":"ええと、確か名前は……","ENG":"That's right. But I think the name was…","TWN":"對啊，只是名字……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"친절과 정성으로 모시는 호라이즌 투자기금입니다.","JPN":"誠実に、親切に、真心を込めておもてなしするホライズン・ファンドです。","ENG":"At Horizon Finance, the customer comes first.","TWN":"竭誠為您服務的地平線金融。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"대출 상담을 하러 오셨습니까, 레이첼.","JPN":"ローンの相談でいらっしゃったのですか、レイチェル。","ENG":"Have you come to apply for a loan, Rachel?","TWN":"瑞秋，你有資金需求嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"호라이즌!!","JPN":"ホライズン！！","ENG":"Horizon!!","TWN":"地平線！！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"숨은 안 막히지만 제 프레임을 팔로 조이는 이유에 대해 설명해 주십시오. 레이첼.","JPN":"息は苦しくありませんが、私のフレームを腕で締める理由について説明してください、レイチェル。","ENG":"While it is impossible to suffocate me, I would like to know why you are applying pressure on my frame with your arms, Rachel.","TWN":"瑞秋，雖然我還能呼吸，但可以請你解釋一下，為什麼要勒緊我的軀殼嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"너 재판 받았다며! 얘기 다 들었어! 게다가……!","JPN":"アンタの裁判の話は聞いたよ！　それに……！","ENG":"I heard you were on trial! I heard about it all! And…","TWN":"我聽說你受審！我都聽說了！而且……！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"게다가……. 그 무서운 아저씨들이랑 싸우기도 하고…….","JPN":"それに……あの怖いおじさんたちと戦って……","ENG":"And... You even fought those scary men…","TWN":"而且……你還有和那個可怕的叔叔吵架……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"재판 결과, 보시는 대로 되었습니다.","JPN":"裁判の結果、ご覧のとおり平気です。","ENG":"The trial concluded in my liberation, as you can see.","TWN":"審判結果，就如你現在所看到的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"코핀 컴퍼니의 주선으로 증언들이 들어온 덕분에 누명은 피할 수 있었습니다.","JPN":"コフィンカンパニー主導のもとで証言があったおかげで、濡れ衣は晴らされました。","ENG":"Thanks to the Coffin Company's mediation, testimony was secured to dispel the false charges against me.","TWN":"都是因為有科芬公司替我找到證據，我才能洗刷污名。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 제프티 바이오테크의 실상이 알려져서 무력 사용의 필요성을 인정 받아……","JPN":"そしてジェフティ・バイオテックの真相が明かされ、武力行使の必要性が認められ……","ENG":"And when Jehuty Biotech's true exploits were unveiled, the court ruled in favor of my need to employ kinetic measures…","TWN":"再加上傑夫堤生物科技的真面目曝光後，我使用武力的必要性也獲得認可……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"몇 가지 제약 외에는 자유로워졌습니다.","JPN":"いくつかの制約はありますが、自由の身になりました。","ENG":"Save for a few constraints, I am free as a lark, as you humans say.","TWN":"排除一些限制外，其他都是自由的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"샤레이드의 전폭적인 지원을 받고 있었기 때문에, 수사 결과는 대외적으로 공표할 수는 없다더군요.","JPN":"例の会社がシャレードから全面的な支援を受けていたので、捜査結果は対外的に公表できないと言われましたが。","ENG":"They could not, however, publicly release the findings of the investigation given the immense support Jehuty Biotech had from Charade.","TWN":"由於受到查雷德全力的支持，搜查結果無法對外公開。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"다행이다……. 평생 감옥에 있을 줄 알았잖아…….","JPN":"よかった……一生刑務所暮らしになると思っていたの……","ENG":"Thank goodness… I was afraid you'd end up in jail for life…","TWN":"太好了……我還以為你這輩子都要吃牢飯了……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런데 제약이라니? 수갑은 안 차고 있는데?","JPN":"ところで制約って？　手錠は見当たらないけど？","ENG":"But what's this about constraints? I don't see you wearing any cuffs.","TWN":"不過限制是什麼？你沒帶手銬啊？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이것저것 많습니다. 가령 관리국의 작전에 협조하라거나 말이죠.","JPN":"色々あります。たとえば、管理局の作戦に協力しろとか。","ENG":"There's quite a few, actually. For instance, I am to cooperate with the Administration's operations.","TWN":"很多，像是支援管理局的作戰之類的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"담당자 이야기로는 최상부에서 모종의 압력이 들어왔다고도 합니다만.","JPN":"担当者の話では、最上部から何らかの圧力がかかってきたそうですが。","ENG":"My lawyer suspects that there has been a certain amount of pressure levied by the highest echelons of the Administration's leadership.","TWN":"據負責人的說法，是有來自最高層的某種壓力。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"궁상맞은 이야기는 이쯤 하고, 입원 생활로 고생했을 레이첼에게 마실 것이라도 드리겠습니다.","JPN":"つまらない話はこの辺にして、入院生活で苦労したレイチェルに飲み物でも出します。","ENG":"Enough of this boring legal talk. Perhaps I can offer you a beverage to celebrate your release from the hospital.","TWN":"我的事就說到這裡，給住院的瑞秋來點喝的吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 그럼 난 위스키!","JPN":"そうね。それじゃあ、アタシはウイスキー！","ENG":"Ooh, then I'd like some whiskey, please!","TWN":"喔！那我要威士忌！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저희 사무실은 미성년자에게 술을 주지 않습니다.","JPN":"うちの事務所では未成年者にお酒は提供しません。","ENG":"This office strictly complies with the legal drinking age.","TWN":"我們辦公室不提供未成年酒類。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아깝다. 원래 퇴원하고 나온 다음에는 맛깔나게 한 잔 캬-! 해 줘야 하는데.","JPN":"ざんねーん。退院祝いに一杯飲んで、くう～！　酒がうまい！　ってやるのがロマンだったのに。","ENG":"Aw, shucks. I was looking forward to downing a shot after getting out of the hospital. You know, like they do in movies.","TWN":"真可惜～本來想說出院後可以痛快乾～一杯的！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"어디서 보고 들은 건 있어 가지고 주접이시군요.","JPN":"入院中にドラマを観すぎたようですね。","ENG":"You've been watching too many movies, indeed.","TWN":"這又是從哪來聽來的？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 레이첼, 확인차 물어 보겠습니다.","JPN":"それでレイチェル、確認のため一つ聞きたいことがあります。","ENG":"Speaking of legal age, I do something I wish verify with you.","TWN":"所以，瑞秋，我跟你確認一下。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"현재 독립을 준비해야 할 상황입니까.","JPN":"現在、独立を準備しなければならない状況ですか。","ENG":"Are you at a juncture where you must now move out and stand on your own?","TWN":"你現在是必須預備獨立的時候嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"윽. 갑자기 현실적인 이야기로 찌르긴.","JPN":"むう、急に現実的な話か。","ENG":"Ugh. Way to get all serious and realistic all of a sudden.","TWN":"唔，怎麼突然問我這麼現實的問題？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"맞아. 다 컸는데 언제까지 보육원에 신세 지고 있을 수는 없으니까.","JPN":"そうね。もう少しで成人するから、いつまでも孤児院のお世話になるわけにはいかないね。","ENG":"But you're right. I can't mooch off the orphanage all my life. I'm too old for that now.","TWN":"沒錯，我都長大了，也不好意思一直賴在育幼院。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 제 사무실에서 일하시죠. 월급은 섭섭하지 않게 지급하겠습니다.","JPN":"ならば私の事務所で働いてください。給料は人並みに支給します。","ENG":"Then I extend an invitation to work in my office. I assure you that the paycheck will not be disappointing.","TWN":"那你來我辦公室工作吧。薪水不會讓你失望的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어……? 정말?","JPN":"え……ほんと……？","ENG":"Huh…? Really?","TWN":"嗯……？真的嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"헤헤, 스카우트라니 좋지만 어쩐다. 나는 사채업이랑은 관련이 없는 사람인데.","JPN":"ヘヘッ、スカウトは嬉しいけどどうしよう。アタシは闇金業界にはまったく知識がないの。","ENG":"Wow, I'm flattered that you'd make me a job offer… But I'm afraid I know nothing about being a loan shark.","TWN":"嘿嘿，有人挖角當然好，但我沒當過放高利貸的欸？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"괜찮습니다. 얼굴이 팔릴 대로 팔려서 사채업만으로 먹고 살기에는 글렀거든요.","JPN":"大丈夫です。私の顔は知られすぎて、闇金融だけで食べていくには厳しいです。","ENG":"Don't worry. You are already too well known among this community to shake down anyone for payment.","TWN":"沒問題，現在已經不是靠放高利貸就活得下去的時代。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"간판을 보셨겠지만, 저는 앞으로 조금 더 떳떳하고 장기적인 투자도 계획하고 있습니다.","JPN":"すでに看板を見ていると思いますが、私はこれからもう少し堂々とした、長期的な投資を計画しています。","ENG":"As you may have noted in the new sign, I plan on investing in more… sanitary endeavors in the long term.","TWN":"你應該也有看到招牌。我現在正在規劃可以長期經營的正當投資。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"장기적인 투자? 암호화폐 말이야?","JPN":"長期的な投資？　暗号通貨のこと？","ENG":"A long term investment? Like cryptocurrency?","TWN":"長期投資？你是指加密貨幣嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……싹수가 있는 휴먼의 장래에 투자하는 겁니다.","JPN":"……見込みあるヒューマンの将来に投資することです。","ENG":"…I mean an investment in promising humans.","TWN":"……就是投資未來是潛力股的人類。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그거 내 얘기야?! 어쩐지 아까부터 빤히 보더라!","JPN":"それは私の話！？　どうりでさっきからじろじろ見ていたのねー！","ENG":"You mean me? No wonder you've been staring at me funny!","TWN":"就是我喔？！難怪你從剛剛就一直盯著我！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼은 탈락입니다.","JPN":"レイチェルは候補から脱落です。","ENG":"You do not make the cut.","TWN":"瑞秋，淘汰。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들이 장학재단이라고 부르는 것과 유사하죠. 용병도 대상이니 범주는 더 넓습니다만.","JPN":"ヒューマンが奨学財団と呼ぶものと似ています。傭兵も対象なので対象範囲はもっと広いですが。","ENG":"This would be akin to what humans call a scholarship foundation. Though the range of eligibility is broader, as it will include mercenaries.","TWN":"就類似人類說的獎學金制度。對象也包含傭兵，範圍很廣。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"금전 문제로 교육을 받지 못하는 휴먼이나, 가난한 지역의 의뢰를 염가로 받아 주는 용병 등…….","JPN":"金銭問題で教育を受けられないヒューマンや、貧しい地域からの依頼を安価で受注してくれる傭兵など……","ENG":"It will aid humans such as those who cannot afford education, or mercenaries that take jobs at minimal rates for impoverished neighborhoods.","TWN":"因為錢的關係而無法上學的人類，或是在貧窮的地區，只能低價接受委託的傭兵等……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 장래가 기대되는 휴먼들에게 저부담 장기 대출을 지원하겠다는 겁니다.","JPN":"将来が期待されるヒューマンたちに、低負担で長期貸出を支援するのです。","ENG":"The goal is to provide long-term low-interest loans to such humans with promising futures.","TWN":"針對未來有潛力的人類，提供低利率的長期融資。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"오오……. 꿈이 참 크시군요, 호라이즌 선생.","JPN":"おお……とても大きい夢ですね、ホライズン先生。","ENG":"Ooh… How ambitious of you, Dr. Horizon.","TWN":"哇喔……你的野心很大喔，地平線老師。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런데 갑자기 왜?","JPN":"てか急になんで？","ENG":"But where did you get this idea all of a sudden?","TWN":"但是爲什麼突然？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"관리국이 사채업자랑 타협하면 모양새가 나쁘다고 하더군요.","JPN":"管理局が闇金業者と協力すると面子が立たないと言われました。","ENG":"The Administration expressed concerns over the optics of reaching a compromise with a loan shark business.","TWN":"因為管理局說和高利貸業者和解的話，對他們的形象不好。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 번듯한 얼굴이 필요해졌습니다.","JPN":"なので、堂々と表に出せる事業をする必要があります。","ENG":"Hence this need for a more ostensibly legitimate front.","TWN":"所以需要長相端正的臉孔。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"어떻습니까, 레이첼?","JPN":"どうですか、レイチェル？","ENG":"What do you think, Rachel?","TWN":"怎麼樣，瑞秋？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그렇다면야 뭐! 독립자금 모으는 겸 열심히 해야지!","JPN":"そういうことね！　独立資金を貯めるのを兼ねて頑張らなきゃだ！","ENG":"Well, in that case! I'd better work hard to save enough till I can move out!","TWN":"你都這麼說了！我會一邊認真工作，一邊存獨立基金的！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"좋습니다. 입사를 환영합니다.","JPN":"いいでしょう。入社おめでとうございます。","ENG":"Good. Welcome to the company.","TWN":"很好，歡迎你加入我們公司。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"축하의 박수 짝짝.","JPN":"お祝いの拍手、パチパチパチ。","ENG":"Congratulatory applause. Clap clap.","TWN":"拍個手以示歡迎，拍拍。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러면 환영식도 끝냈으니 사원 목록을 갱신해야겠군요.","JPN":"それでは歓迎式も終わったので、社員リストを更新しなければなりませんね。","ENG":"Now that the welcome party is over, I should update the staff roster.","TWN":"歡迎儀式結束了，來更新員工清冊吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어? 너……. 이 사진 어디서 가져 온 거야?","JPN":"え？　あんた……この写真どこから持ってきたの？","ENG":"Huh? Hey… Where did you get this picture?","TWN":"嗯？你…… 這照片是從哪裡來的？"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"지난번에 레이첼과 함께 보육원에서 묵을 때 입수했습니다.","JPN":"この前レイチェルと孤児院に泊まった時、入手したものです。","ENG":"I acquired it during my temporary stay with you at the orphanage.","TWN":"這是上次和你一起去育幼院過夜時拿到的。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"야! 너 그거 완전 도둑질이잖아!","JPN":"えーそれって完全に窃盗じゃない！","ENG":"Come on! That's stealing!","TWN":"喂！你這不是拿，是偷吧！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"괜찮습니다. 보육원장도 양심이 있으면 사진 한 장 뜯은 걸로 뭐라 하진 않겠죠.","JPN":"問題ありません。院長も良心があるなら、写真一枚なくなったことでとやかく言わないでしょう。","ENG":"Don't worry. I'm sure the headmaster won't raise a fuss over a photo if he has any conscience.","TWN":"沒關係，育幼院長有良心的話，應該不會跟我計較區區一張照片吧？"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어휴, 진짜…….","JPN":"もう、まったく……","ENG":"Oh, jeez…","TWN":"真是的……"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"불만 있습니까, 휴먼?","JPN":"文句がありますか、ヒューマン？","ENG":"Something troubling you, human?","TWN":"有問題嗎，人類？"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"당연하지. 이렇게 붙여 두면 내가 꼭 굴러들어온 돌 같잖아.","JPN":"そりゃそうよ。この貼り方だと、アタシだけ浮いてるじゃない。","ENG":"Well, yeah. This makes me look like the third, or I guess, fourth wheel now.","TWN":"當然！你這樣貼，搞得我的臉很突兀欸！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"과대평가는 좋지 않습니다.","JPN":"自意識過剰は良くありません。","ENG":"I would advise against such an overestimation of yourself for now.","TWN":"我不喜歡說話加油添醋。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어휴, 어떻게 된 애가 한마디도 안 져…….","JPN":"まったく、あんたって一言も負けないんだから……","ENG":"Ugh, you've got a comeback for everything, don't you…","TWN":"真是的，每句話都要頂回來……"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"하지만 좋아. 그릴 얼굴이 하나 더 늘었으니까 분발해야겠네.","JPN":"いいよ！　描く顔がもう一つ増えたから頑張らないと！","ENG":"But I guess it's okay. This just means I have to work harder to paint one more face in.","TWN":"不過我喜歡！現在又多一個人要畫，我要更努力囉！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"무슨 말씀이십니까, 휴먼.","JPN":"どういう意味ですか、ヒューマン。","ENG":"What do you mean, human?","TWN":"你在說什麼，人類？"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네 아르바이트 첫날. 선물 아직 못 줬잖아.","JPN":"あんたのアルバイト初日のお祝い。プレゼントをまだ渡してないでしょ。","ENG":"Remember that first day you worked part time? I haven't given your gift yet.","TWN":"你第一天打工的禮物我都還沒送你呢！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"내가 부를 때까지 여기서 나오면 안 돼, 알았지?","JPN":"アタシが呼ぶまでここから出ちゃダメだよ。わかった？","ENG":"Don't come outside till I call for you, okay?","TWN":"在我叫你之前，不可以離開這裡喔！知道嗎？"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"사무실 벽에 낙서하면 경범죄로 신고하겠습니다.","JPN":"事務室の壁に落書きしたら軽犯罪で通報します。","ENG":"I will press charges against you if you're thinking of defacing the office walls.","TWN":"你敢在辦公室牆上亂塗鴉的話，我會報警抓你。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"낙서라니! 세상 사람들이 다 알 작품이 될 거라고!","JPN":"落書きだって！？　これは将来世界中の人に知れ渡る作品になるんだよ！？","ENG":"Defacing?! Come on, this is going to become a masterpiece!","TWN":"什麼亂塗鴉！這將成為世界名作好嗎！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그럼 저도 감독해야겠습니다. 당신이라면 절 실제보다 과하게 어린 모습으로 그릴 테니까요.","JPN":"それだと私が監修する必要があります。あなたなら私を実際より過度に幼い姿で描きますからね。","ENG":"Then I must stay and supervise. Otherwise, I am certain you will paint me to appear far younger than I actually look.","TWN":"那我必須監工。因為你會把我畫得比實際還年輕很多！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아차. 젖병 물려 주려고 했는데 들켰네.","JPN":"あちゃー哺乳瓶を持たせようとしたの、バレちゃったか。","ENG":"Oops. You got me. I was going to stick a pacifier in your mouth.","TWN":"哎呀！被抓包，本來想替你畫個奶瓶的～"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런데 호라이즌, 관리국 사람들이랑 얘기했으면 혹시 그 작전 얘기 들었어? 빌딩에서 벌어졌다던?","JPN":"ていうかホライズン、管理局の人と話してるならあの作戦の話は聞いた？　ビルで起きたっていう。","ENG":"By the way, Horizon. If you've been talking with the Administration, have you heard about that one operation? You know, the one at a building?","TWN":"不過，地平線，你有和管理局談過的話，那你有聽說那個作戰的事嗎？聽說發生在大樓裡欸？"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"섬멸 작전 말씀이십니까. 일단은 저도 한 몫 거들었습니다.","JPN":"殲滅作戦ですか。一応私も活躍しています。","ENG":"You must mean the elimination operation. I suppose you could say I had a hand in that.","TWN":"你是指殲滅戰嗎？總之我也有參一腳。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그래! 바로 그거야! 내 불안감을 날려 버리려면 그런 화끈한 얘기가 필요해!","JPN":"そう！　まさにそれ！　私の不安感を吹き飛ばすには、そういうスリリングな話が必要なの！","ENG":"Nice! That's what I'm talking about! That's exactly the sort of kick-ass story I need to keep my anxiety away!","TWN":"沒錯！就是那個！要消除我的不安的話，就需要這種大快人心的事情！"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……작업하는 동안 말씀드리겠습니다. 오디오가 비면 지루해질 테니까요.","JPN":"……作業中に話すとしましょう。オーディオがないと退屈してしまうでしょうから。","ENG":"…Then I shall tell you all about it while you work. A lengthy silence could get awfully boring, after all.","TWN":"……工作中跟你說一下，沒有音響會很無聊。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"리타. 대시. 이제 저는 당신들이 없는 시간을 준비하려고 합니다.","JPN":"リタ、ダッシュ。私はあなたたちのいない時を迎えようとしています。","ENG":"Rita. Dash. I am now preparing for a period without you two.","TWN":"麗塔、黛西，我現在要習慣沒有你們的時間。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"얼마나 긴 시간이 될지 모르겠지만, 당신들에게서 배운 대로 시도해 보려고 합니다.","JPN":"どれほど長い時間になるかわかりませんが、あなたたちから教わったとおりに試してみようと思います。","ENG":"I do not know how long this period will last, but I will endeavor to do as you have taught me.","TWN":"雖然不知道要花多長的時間，但我會照你們教我的去試試看。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"실패도, 실수도 겪을 수 있습니다. 저는 결함품이니 당신들만큼 잘하지 못하겠죠. ","JPN":"失敗もミスもあるでしょう。私は欠陥品ですから、あなたたちほど上手くやっていけないかもしれません。","ENG":"I may fail or make mistakes. Being the defective program that I am, I may never excel at this as much as you. ","TWN":"很有可能會經歷失敗或錯誤，誰叫我是瑕疵品，沒辦法像你們那麼棒。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 앞으로, 두 번 다시 울지 않게.","JPN":"ですから、これからは二度と泣かないように。","ENG":"So lest there be any further cause for weeping…","TWN":"以後我們都不再哭泣，"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"눈물 요정아. 달아나라. 뚝.","JPN":"涙の妖精よ、飛んでけ。","ENG":"Go away, tear fairy. Shoo.","TWN":"眼淚仙子，快快走。"},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"                                                                                                 <color=#ffd34c>울지 않은 너를 위해</color> Fin.","JPN":"                                                                                                 <color=#ffd34c>泣かない君のために</color> Fin.","ENG":"                                                                                                 <color=#ffd34c>For the Uncrying</color> Complete","TWN":"                                                                                                 <color=#ffd34c>為了沒哭的妳</color> Fin."},"stage":{"bg":"HORIZON_01_A","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};